public class DiscountCalculator {
    /**
     * Calculates the discount amount based on original price and discount percentage.
     * @param originalPrice The original price of the item. Must be non-negative.
     * @param discountPercent The discount percentage. Must be between 0 and 100.
     * @return The calculated discount amount.
     * @throws IllegalArgumentException If input values are invalid.
     */
    public static double calculateDiscount(double originalPrice, int discountPercent) {
        // Validate originalPrice is non-negative
        if (originalPrice < 0) {
            throw new IllegalArgumentException("Original price cannot be negative.");
        }
        // Validate discountPercent is within valid range
        if (discountPercent < 0 || discountPercent > 100) {
            throw new IllegalArgumentException("Discount percentage must be 0-100.");
        }
        // Calculate discount amount
        double discountAmount = (originalPrice * discountPercent) / 100;
        return discountAmount;
    }

    public static void main(String[] args) {
        try {
            // Example call with price 200 and 15% discount
            double discount = calculateDiscount(200, 15);
            System.out.println("Discount amount: " + discount);
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}
