/// Merges two sorted arrays of integers into a single sorted array.
///
/// # Parameters
/// - `arr1`: A sorted slice of integers.
/// - `arr2`: Another sorted slice of integers.
///
/// # Returns
/// A new `Vec<i32>` containing all elements from `arr1` and `arr2` in sorted order.
///
/// # Example
/// ```
/// let arr1 = [1, 3, 5];
/// let arr2 = [2, 4, 6];
/// let merged = merge_sorted_arrays(&arr1, &arr2);
/// assert_eq!(merged, vec![1, 2, 3, 4, 5, 6]);
/// ```
pub fn merge_sorted_arrays(arr1: &[i32], arr2: &[i32]) -> Vec<i32> {
    let mut result = Vec::with_capacity(arr1.len() + arr2.len());
    let mut i = 0;
    let mut j = 0;

    while i < arr1.len() && j < arr2.len() {
        if arr1[i] <= arr2[j] {
            result.push(arr1[i]);
            i += 1;
        } else {
            result.push(arr2[j]);
            j += 1;
        }
    }

    while i < arr1.len() {
        result.push(arr1[i]);
        i += 1;
    }

    while j < arr2.len() {
        result.push(arr2[j]);
        j += 1;
    }

    result
}
