// AggregateMetrics calculates the average, maximum, and minimum values from a slice of integers.
// Parameters:
//   nums - slice of integers to process
// Returns:
//   Three integers representing the average (rounded to the nearest integer), maximum, and minimum values.
func AggregateMetrics(nums []int) (int, int, int) {
    if len(nums) == 0 {
        return 0, 0, 0
    }
    sum := 0
    max := nums[0]
    min := nums[0]
    for _, num := range nums {
        sum += num
        if num > max {
            max = num
        }
        if num < min {
            min = num
        }
    }
    average := sum / len(nums)
    return average, max, min
}
