import os
import logging

def stream_files(directory_path, log_file):
    """Process text files in a directory with .txt extension, logging events and errors.

    Args:
        directory_path (str): Path to the directory to process.
        log_file (str): Filename for logging processing events and errors.
    """
    logging.basicConfig(
        filename=log_file,
        level=logging.INFO,
        format='%(asctime)s - %(levelname)s - %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )

    try:
        for root, _, files in os.walk(directory_path):
            for file in files:
                if file.endswith('.txt'):
                    file_path = os.path.join(root, file)
                    logging.info(f"Processing initiated for file: {file}")
                    try:
                        with open(file_path, 'r') as f:
                            _ = f.read()
                        logging.info(f"File '{file}' processed successfully.")
                    except (OSError, IOError) as e:
                        logging.error(f"Error processing file '{file}': {str(e)}")
    except (OSError, IOError) as e:
        logging.error(f"Error accessing directory {directory_path}: {str(e)}")
