import (
    "strconv"
    "strings"
)

/*
compressString takes a string and compresses consecutive repeated characters into
the character followed by their count. If the compressed string is not shorter
than the original, the original string is returned.

Parameters:
    s : string - The input string to be compressed.

Returns:
    string - The compressed string if shorter; otherwise, the original string.
*/
func compressString(s string) string {
    if len(s) == 0 {
        return s
    }

    runes := []rune(s)
    var builder strings.Builder

    current := runes[0]
    count := 1

    for i := 1; i < len(runes); i++ {
        if runes[i] == current {
            count++
        } else {
            builder.WriteRune(current)
            builder.WriteString(strconv.Itoa(count))
            current = runes[i]
            count = 1
        }
    }

    builder.WriteRune(current)
    builder.WriteString(strconv.Itoa(count))

    compressed := builder.String()
    if len(compressed) >= len(s) {
        return s
    }
    return compressed
}
