def consolidate_inventory(current_inventory, new_stock):
    # Merges two inventory dictionaries, summing quantities for common items
    # Converts None inputs to empty dicts, validates input types and quantity types
    # Inputs: dictionaries with item names (str) as keys, integer quantities as values
    current_inventory = current_inventory if current_inventory is not None else {}
    new_stock = new_stock if new_stock is not None else {}
    if not isinstance(current_inventory, dict) or not isinstance(new_stock, dict):
        raise TypeError("current_inventory and new_stock must be dictionaries.")
    for item, qty in current_inventory.items():
        if not isinstance(qty, int):
            raise TypeError(f"Item '{item}' has non-integer quantity.")
    for item, qty in new_stock.items():
        if not isinstance(qty, int):
            raise TypeError(f"Item '{item}' has non-integer quantity.")
    merged = current_inventory.copy()
    for item, qty in new_stock.items():
        merged[item] = merged.get(item, 0) + qty
    return merged
