pub struct Statistics {
    pub mean: f64,
    pub median: f64,
    pub mode: i32,
}

/// Computes the mean, median, and mode of a list of integers.
///
/// # Parameters
/// - `numbers`: A slice of integers to analyze.
///
/// # Returns
/// A `Statistics` struct containing the mean, median, and mode.
///
/// # Examples
/// ```
/// let numbers = vec![3, 1, 2, 3, 4, 4, 4];
/// let stats = compute_stats(&numbers);
/// assert_eq!(stats.mean, 3.0);
/// assert_eq!(stats.median, 3.0);
/// assert_eq!(stats.mode, 4);
/// ```
pub fn compute_stats(numbers: &[i32]) -> Statistics {
    let sum: i64 = numbers.iter().map(|&n| n as i64).sum();
    let mean = sum as f64 / numbers.len() as f64;

    let mut sorted = numbers.to_vec();
    sorted.sort_unstable();
    let mid = sorted.len() / 2;
    let median = if sorted.len() % 2 == 0 {
        (sorted[mid - 1] as f64 + sorted[mid] as f64) / 2.0
    } else {
        sorted[mid] as f64
    };

    use std::collections::HashMap;
    let mut counts = HashMap::new();
    for &num in numbers {
        *counts.entry(num).or_insert(0) += 1;
    }
    let mode = counts
        .into_iter()
        .max_by_key(|&(num, count)| (count, std::cmp::Reverse(num)))
        .unwrap()
        .0;

    Statistics { mean, median, mode }
}
