// SumSlice computes the total sum of a slice of integers.
// It returns the computed sum and an error if integer overflow occurs during the summation.
// Parameters:
//   nums - slice of integers to sum
// Returns:
//   int - the sum of the integers
//   error - non-nil if the sum exceeds the maximum or minimum integer value
func SumSlice(nums []int) (int, error) {
    sum := 0
    for _, num := range nums {
        temp := sum + num
        if sum > 0 && num > 0 && temp < 0 {
            return temp, fmt.Errorf("integer overflow")
        }
        if sum < 0 && num < 0 && temp > 0 {
            return temp, fmt.Errorf("integer underflow")
        }
        sum = temp
    }
    return sum, nil
}
