/* Aggregates stock records to compute total stock per product. Returns a MutableMap where keys are product IDs and values are summed stocks. */
fun calculateStockSummary(records: List<Map<String, Any>>): MutableMap<String, Int> {
    val summarizedStock = mutableMapOf<String, Int>()
    for (product in records) {
        val productId = product["product_id"] as String
        val stock = product["stock"] as Int
        summarizedStock[productId] = summarizedStock.getOrDefault(productId, 0) + stock
    }
    return summarizedStock
}
