// MaxSubarraySum calculates the maximum sum of any contiguous subarray using Kadane's Algorithm.
// It handles edge cases: returns 0 for an empty array, and the highest single element if all numbers are negative.
// Parameters:
//   nums: an array of integers.
// Returns:
//   The maximum sum of any contiguous subarray, or appropriate value for edge cases.
func MaxSubarraySum(nums []int) int {
    if len(nums) == 0 {
        return 0
    }

    allNegative := true
    maxElement := nums[0]
    for _, num := range nums {
        if num >= 0 {
            allNegative = false
        }
        if num > maxElement {
            maxElement = num
        }
    }
    if allNegative {
        return maxElement
    }

    maxEndingHere, maxSoFar := 0, 0
    for _, num := range nums {
        current := maxEndingHere + num
        if num > current {
            maxEndingHere = num
        } else {
            maxEndingHere = current
        }
        if maxEndingHere > maxSoFar {
            maxSoFar = maxEndingHere
        }
    }
    return maxSoFar
}
