/**
 * Evaluates a reverse Polish notation (RPN) expression provided as a string.
 * The expression consists of integers and the operators +, -, *, / separated by spaces.
 * 
 * @param expression The RPN expression to evaluate.
 * @return The result of the evaluated expression.
 * @throws ArithmeticException If a division by zero is attempted.
 * @throws RuntimeException If the expression is malformed (invalid tokens, insufficient operands, extra operands).
 */
public static double evaluateRPNExpression(String expression) {
    Deque<Double> stack = new ArrayDeque<>();
    String[] tokens = expression.split("\\s+"); // Split on whitespace
    for (String token : tokens) {
        if (token.isEmpty()) {
            continue; // Skip empty tokens from leading/trailing spaces
        }
        // Check if the token is an operator
        if ("+-*/".contains(token) && token.length() == 1) {
            // Handle operator
            if (stack.size() < 2) {
                throw new RuntimeException("Insufficient operands for operator " + token);
            }
            double b = stack.pop();
            double a = stack.pop();
            switch (token) {
                case "+":
                    stack.push(a + b);
                    break;
                case "-":
                    stack.push(a - b);
                    break;
                case "*":
                    stack.push(a * b);
                    break;
                case "/":
                    if (b == 0) {
                        throw new ArithmeticException("Division by zero");
                    }
                    stack.push(a / b);
                    break;
            }
        } else {
            // Handle operand
            try {
                int num = Integer.parseInt(token);
                stack.push((double) num); // Store as double for division cases
            } catch (NumberFormatException e) {
                throw new RuntimeException("Malformed expression: invalid token '" + token + "'");
            }
        }
    }
    if (stack.size() != 1) {
        throw new RuntimeException("Malformed expression: incorrect number of operands");
    }
    return stack.pop();
}
